// dedicated detox metro port - avoids conflict with other dev servers on 8081.
// the android dir is gitignored (regenerated by expo prebuild), so this plugin
// re-injects the port into android/gradle.properties on every prebuild.
//
// read by @react-native/gradle-plugin AgpConfiguratorUtils.configureDevServerLocation
// which writes it into the react_native_dev_server_port resource value.
// run-detox.sh and .detoxrc.js default to the same port.
const { withDangerousMod } = require('@expo/config-plugins')
const fs = require('fs')
const path = require('path')

const PORT = 9034
const MARKER = '# detox: dedicated metro port'

module.exports = function withDetoxMetroPort(config) {
  return withDangerousMod(config, [
    'android',
    async (config) => {
      const propsPath = path.join(
        config.modRequest.platformProjectRoot,
        'gradle.properties'
      )

      if (!fs.existsSync(propsPath)) {
        return config
      }

      let contents = fs.readFileSync(propsPath, 'utf8')

      if (contents.includes(MARKER)) {
        return config
      }

      contents +=
        `\n${MARKER}\n` +
        `# read by @react-native/gradle-plugin AgpConfiguratorUtils.configureDevServerLocation,\n` +
        `# which writes this into the react_native_dev_server_port resource.\n` +
        `# detox runner (run-detox.sh) and .detoxrc.js default to the same port.\n` +
        `reactNativeDevServerPort=${PORT}\n`

      fs.writeFileSync(propsPath, contents)
      return config
    },
  ])
}
